CREATE OR REPLACE FUNCTION reports_under(p_manager BIGINT)
RETURNS TABLE (id BIGINT, name TEXT) AS $$
DECLARE
  v_added INT;
BEGIN
  CREATE TEMP TABLE tmp_reports (id BIGINT, name TEXT) ON COMMIT DROP;
  INSERT INTO tmp_reports
  SELECT e.id, e.name FROM employees e WHERE e.manager_id = p_manager;

  LOOP
    INSERT INTO tmp_reports
    SELECT e.id, e.name
    FROM   employees e
    JOIN   tmp_reports t ON e.manager_id = t.id
    LEFT JOIN tmp_reports t2 ON t2.id = e.id
    WHERE  t2.id IS NULL;

    GET DIAGNOSTICS v_added = ROW_COUNT;
    EXIT WHEN v_added = 0;
  END LOOP;

  RETURN QUERY SELECT * FROM tmp_reports;
END;
$$ LANGUAGE plpgsql;

